Filter Functions

filterByTimeRange
Works with any TimeSeriesElement:
auto series = std::make_shared&lt;AnalogTimeSeries&gt;();
// ... populate ...

// Lazy view - no data copied
auto filtered = filterByTimeRange(
    series-&gt;elementsView(),
    TimeFrameIndex(100),
    TimeFrameIndex(200));

for (auto const& elem : filtered) {
