// ... populate ...

std::unordered_set&lt;EntityId&gt; selected{EntityId(1), EntityId(3)};
auto filtered = filterByEntityIds(events-&gt;elementsView(), selected);

for (auto const& event : filtered) {
    // Only events with EntityId 1 or 3
