Example 3: Cross-Type Operations
// Find overlapping time ranges across different series types
template&lt;TimeSeriesElement T1, TimeSeriesElement T2&gt;
std::optional&lt;std::pair&lt;TimeFrameIndex, TimeFrameIndex&gt;&gt;
findOverlap(T1 const& range1, T2 const& range2)
{
    auto bounds1 = timeBounds(range1);
    auto bounds2 = timeBounds(range2);

    if (!bounds1 || !bounds2) return std::nullopt;

    auto [min1, max1] = *bounds1;
    auto [min2, max2] = *bounds2;

    auto overlapStart = std::max(min1, min2);
    auto overlapEnd = std::min(max1, max2);

    if (overlapStart &lt;= overlapEnd) {
        return std::make_pair(overlapStart, overlapEnd);
    }
    return std::nullopt;
}

// Usage with different series types:
auto overlap = findOverlap(
    analogSeries-&gt;elementsView(),
    maskData.elementsView());

Old Pattern → New Pattern

Direct Member Access → Accessor Methods
Before (still works, but deprecated):
// Old: Direct struct member access
for (auto [time, entry] : series.elements()) {
    float val = entry.value;  // Direct member
}
After (preferred):
// New: Accessor method
for (auto const& elem : series.elementsView()) {
    float val = elem.value();  // Accessor method
}


Type-Specific Code → Generic Code
Before:
// Separate functions for each type
void processAnalog(AnalogTimeSeries const& series) {
    for (auto [time, point] : series.elements()) {
        // Analog-specific code
    }
}

void processEvents(DigitalEventSeries const& series) {
    for (auto [time, event] : series.elements()) {
        // Event-specific code
    }
}
After:
// Single generic function
template&lt;TimeSeriesElement T&gt;
void processAnyTimeSeries(std::ranges::input_range auto&& range) {
    for (auto const& elem : range) {
        auto time = elem.time();
        // Works with any time series type
    }
}

// Usage:
processAnyTimeSeries(analogSeries-&gt;elementsView());
processAnyTimeSeries(eventSeries-&gt;elementsView());


Manual Filtering → Filter Utilities
Before:
// Manual filtering
std::vector&lt;EventWithId&gt; filtered;
for (auto const& event : events.view()) {
    if (event.time() &gt;= start && event.time() &lt;= end) {
        if (ids.contains(event.id())) {
            filtered.push_back(event);
        }
    }
}
After:
// Using filter utilities
auto filtered = materializeToVector(
    filterByTimeRangeAndEntityIds(events.view(), start, end, ids));

Lazy Views vs Materialization
Filter functions return lazy views that don’t copy data:
// GOOD: Lazy, no allocation
auto view = filterByTimeRange(series-&gt;elementsView(), start, end);
for (auto const& elem : view) { /* ... */ }

// AVOID: Unnecessary materialization
auto vec = materializeToVector(filterByTimeRange(series-&gt;elementsView(), start, end));
for (auto const& elem : vec) { /* ... */ }  // Vector copy overhead
When to materialize:

Need random access to filtered elements
Need to iterate multiple times
Need data to outlive the source series
Passing to APIs that require vectors

Cache-Optimized Iteration
All time series types use cache optimization for fast iteration:
// Fast: Uses cached contiguous pointers
for (auto const& elem : series-&gt;elementsView()) {
    // Zero virtual dispatch when storage is contiguous
}

// Also fast: elements() uses same optimization
for (auto [time, elem] : series-&gt;elements()) {
    // Cache-optimized path
}

This guide describes the process for creating reusable test fixtures that enable consistent testing between V1 and V2 transform implementations. By decoupling test data creation from the transform-specific API, you can verify that both V1 and V2 produce identical results for the same input data.


The goal is to: 1. Decouple test data from transformation logic 2. Reuse the same test data across V1 and V2 tests 3. Ensure algorithmic consistency between implementations 4. Keep parameter/JSON testing in their respective test files



tests/
└── DataManager/
    └── fixtures/
        ├── MaskAreaTestFixture.hpp      # Shared test data
        ├── AnalogEventThresholdTestFixture.hpp
        └── ...

src/DataManager/
├── transforms/
│   └── Masks/
│       └── Mask_Area/
│           └── mask_area.test.cpp       # V1 tests (uses fixture)
└── transforms/v2/
    └── algorithms/
        └── MaskArea/
            └── MaskArea.test.cpp        # V2 tests (uses same fixture)





Identify the test data patterns in your V1 tests:
// Before: Data creation scattered in V1 tests
TEST_CASE("Mask area calculation", "[mask][area]") {
    auto mask_data = std::make_shared&lt;MaskData&gt;();

    // Data creation mixed with test logic
    std::vector&lt;uint32_t&gt; x1 = {1, 2, 3};
    std::vector&lt;uint32_t&gt; y1 = {1, 2, 3};
    mask_data-&gt;addAtTime(TimeFrameIndex(100), Mask2D(x1, y1), NotifyObservers::No);

    auto result = area(mask_data.get());
    // ... assertions
}



Create a fixture header in tests/DataManager/fixtures/:
// tests/DataManager/fixtures/MyTransformTestFixture.hpp
#ifndef MY_TRANSFORM_TEST_FIXTURE_HPP
#define MY_TRANSFORM_TEST_FIXTURE_HPP

#include "catch2/catch_test_macros.hpp"
#include "DataManager.hpp"
#include "MyDataType.hpp"
#include "TimeFrame/TimeFrame.hpp"
#include "TimeFrame/StrongTimeTypes.hpp"

#include &lt;memory&gt;
#include &lt;map&gt;
#include &lt;string&gt;

class MyTransformTestFixture {
protected:
    MyTransformTestFixture() {
        m_data_manager = std::make_unique&lt;DataManager&gt;();
        m_time_frame = std::make_shared&lt;TimeFrame&gt;();
        m_data_manager-&gt;setTime(TimeKey("default"), m_time_frame);
        populateTestData();
    }

    ~MyTransformTestFixture() = default;

    DataManager* getDataManager() {
        return m_data_manager.get();
    }

    // Map of named test data objects
    std::map&lt;std::string, std::shared_ptr&lt;MyDataType&gt;&gt; m_test_data;

private:
    void populateTestData() {
        // Create each test scenario with a descriptive key
        createData("empty_data", /* ... */);
        createData("single_element", /* ... */);
        createData("multiple_elements", /* ... */);
        createData("edge_case_scenario", /* ... */);
    }

    void createData(const std::string& key, /* ... */) {
        auto data = std::make_shared&lt;MyDataType&gt;();
        // ... populate data ...
        m_data_manager-&gt;setData(key, data, TimeKey("default"));
        m_test_data[key] = data;
    }

    std::unique_ptr&lt;DataManager&gt; m_data_manager;
    std::shared_ptr&lt;TimeFrame&gt; m_time_frame;
};

#endif
Key Design Principles:

Use descriptive keys - Name test data by the scenario, not the expected result
Store both in map and DataManager - Allows direct access and key-based lookup
Document expected results in comments - But don’t encode them in the fixture
Keep fixture minimal - Only data creation, no transform logic




Update the V1 test file to use TEST_CASE_METHOD:
